-- PDX Ops Hub — Histórico de visitantes: 1 ene 2025 → 15 jul 2026
-- Ejecuta este script en Supabase SQL Editor (copia todo y pulsa Run)
-- Si una fecha ya existe solo actualiza los visitantes, no sobreescribe grupos ni otros campos

ON CONFLICT (fecha) DO UPDATE SET visitantes = EXCLUDED.visitantes, updated_at = now();
